import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

import BaseTamplateRequest from '../../consts/BaseTemplateRequest';
import { addRow } from '../../consts/crud';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddRoadSing() {
    const [roads, setRoads] = useState([]);
    const [road_id, setRoadID] = useState('');
    const [image, setFile] = useState('');
    const [latitude, setLatitude] = useState('');
    const [longitude, setLongitude] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handelFileChange = (e) => {
        setFile(e.target.files[0]);
    };

    const submitRoadSing = async (e) => {
        e.preventDefault();
        const read_roads = await readRows('/roads');
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const road_sing = { road_id, image, latitude, longitude };
        await addRow('/roads/sings', road_sing, headers);
        setTimeout(() => {
            setRoadID('');
            alert(read_roads.data);
            setRoads(read_roads.data);
            setLatitude('');
            setLongitude('');
            navigate('/roads/sings');
        }, 5000);
    };

    return (
        <div>
            <BaseTamplateRequest />
            <form className='container' onSubmit={submitRoadSing}>
                <h1>Создание знака на дороге</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дороги</lable>
                    <input 
                        type='text'
                        name='road_id' 
                        value={road_id.road_id} 
                        onChange={(e) => setRoadID(e.target.value)}
                        className='form-input'  
                        placeholder='road_id'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Изображение</lable>
                    <input
                        type='file'
                        name='image'
                        value={image.image} 
                        onChange={handelFileChange}
                        placeholder='image'
                        required  
                        multiple
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Широта</lable>
                    <input 
                        type='text'
                        name='latitude' 
                        value={latitude.latitude} 
                        onChange={(e) => setLatitude(e.target.value)}
                        className='form-input'  
                        placeholder='latitude'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Долгота</lable>
                    <input 
                        type='text'
                        name='longitude' 
                        value={longitude.longitude} 
                        onChange={(e) => setLongitude(e.target.value)}
                        className='form-input'  
                        placeholder='longitude'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Создать
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )
};

export default AddRoadSing;
